// AI sentiment + intent scoring for unanalyzed comments
const headers = { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}` };

// Fetch unanalyzed comments (no sentiment set)
const comments = await this.helpers.httpRequest({
  method: 'GET',
  url: `${process.env.SUPABASE_URL}/rest/v1/comments?sentiment=is.null&select=id,text,platform&order=created_at.desc&limit=50`,
  headers,
});

if (!comments || comments.length === 0) {
  return [{ json: { analyzed: 0, message: 'No unanalyzed comments' } }];
}

// Batch analyze with Claude Haiku
const prompt = `Analyze these ${comments.length} comments. For each, provide:
- sentiment: positive, negative, or neutral
- intent_score: 0.0-1.0 (higher = purchase/interest intent)
- intent_signals: array of detected signals like ["link_request", "price_inquiry", "purchase_intent", "support_request", "praise", "complaint"]

Comments:
${JSON.stringify(comments.map((c, i) => ({ index: i, text: c.text.substring(0, 200), platform: c.platform })))}

Respond ONLY in JSON: [{"index":0,"sentiment":"positive","intent_score":0.3,"intent_signals":["praise"]}]`;

try {
  const aiResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: { 'x-api-key': process.env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    body: JSON.stringify({ model: 'claude-3-5-haiku-20241022', max_tokens: 2048, messages: [{ role: 'user', content: prompt }] }),
  });

  const text = aiResp.content?.[0]?.text || '[]';
  let analyses;
  try { analyses = JSON.parse(text); } catch {
    const m = text.match(/\[[\s\S]*\]/);
    analyses = m ? JSON.parse(m[0]) : [];
  }

  let updated = 0;
  for (const a of analyses) {
    if (a.index !== undefined && comments[a.index]) {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: `${process.env.SUPABASE_URL}/rest/v1/comments?id=eq.${comments[a.index].id}`,
        headers: { ...headers, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          sentiment: a.sentiment || 'neutral',
          intent_score: a.intent_score || 0,
          intent_signals: a.intent_signals || [],
        }),
      });
      updated++;
    }
  }

  return [{ json: { analyzed: updated, total_comments: comments.length } }];
} catch (e) {
  return [{ json: { analyzed: 0, error: e.message } }];
}
